func categoryTotal(cats []db.GetSpendingByCategoryRow) float64 {
	var t float64
	for _, c := range cats {
		t += c.Total
	}
	return t
}

func catPct(amount, total float64) float64 {
	if total == 0 {
		return 0
	}
	return (amount / total) * 100
}

func prevMonthURL(from string) string {
	t := parseYYYYMM(from)
	prev := t.AddDate(0, -1, 0)
	return fmt.Sprintf("/spending?from=%s&to=%s", prev.Format("2006-01-02"), lastDayOf(prev).Format("2006-01-02"))
}

func nextMonthURL(from string) string {
	t := parseYYYYMM(from)
	next := t.AddDate(0, 1, 0)
	return fmt.Sprintf("/spending?from=%s&to=%s", next.Format("2006-01-02"), lastDayOf(next).Format("2006-01-02"))
}

